{
  "commit": {
    "createdAt": "2026-02-15T15:50:48Z",
    "id": "f487e78078bb5e09f3f99793b1c77d80ee377459",
    "message": "Fix dependency conflict: pydantic\u003e=2.11.7 required by fastmcp 2.14.5\n\nfastmcp 2.14.5 requires pydantic\u003e=2.11.7. Our pin at 2.10.5 caused\npip to either downgrade fastmcp to 1.0 (missing http_app) or fail\nresolution entirely. Using \u003e= constraint lets pip resolve freely.\n\nCo-Authored-By: Claude Sonnet 4.5 \u003cnoreply@anthropic.com\u003e\nEntire-Checkpoint: fce56b483b8b"
  },
  "createdAt": "2026-02-15T15:51:08.411892Z",
