     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import { useCallback, useEffect, useRef, useState } from "react";
     5→import { QRCodeSVG } from "qrcode.react";
     6→import { useCamera } from "@/hooks/useCamera";
     7→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     8→import { usePoseDetection } from "@/hooks/usePoseDetection";
     9→import { useMiraVideoAvatar } from "@/hooks/useMiraVideoAvatar";
    10→import type { MiraEmotion } from "@/components/ui/mira-video-avatar";
    11→import { useDeepgramSTT, type DeepgramSTTConfig } from "@/hooks/useDeepgramSTT";
    12→import { detectEmotionFromText } from "@/lib/emotion-parser";
    13→import { MiraVideoAvatar } from "@/components/ui/mira-video-avatar";
    14→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    15→import { ClothingCanvas, type FitMethod } from "@/components/mirror/ClothingCanvas";
    16→import { DebugOverlay } from "@/components/mirror/DebugOverlay";
    17→import { SpeechDisplay } from "@/components/mirror/SpeechDisplay";
    18→import { OutfitDots } from "@/components/mirror/OutfitDots";
    19→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    20→import PriceStrip, { type PriceStripItem } from "@/components/mirror/PriceStrip";
    21→import SessionRecap from "@/components/mirror/SessionRecap";
    22→import { socket } from "@/lib/socket";
    23→import { skipQueueUser, getSTTConfig } from "@/lib/api";
    24→import type { DetectedGesture, GestureType } from "@/types/gestures";
    25→import type { PoseResult } from "@/types/pose";
    26→import type { ClothingItem } from "@/types/clothing";
    27→import ProductCarousel, { type ProductCard } from "@/components/mirror/ProductCarousel";
    28→import { LikedItemsTray, type LikedOutfitThumbnail } from "@/components/mirror/LikedItemsTray";
    29→import { processToolResult } from "@/lib/process-tool-result";
    30→
    31→type KioskState = "attract" | "waiting" | "session" | "recap";
    32→
    33→interface ActiveUser {
    34→  id: string;
    35→  name: string;
    36→}
    37→
    38→const PHONE_URL = process.env.NEXT_PUBLIC_PHONE_URL || "https://mirrorless.vercel.app/phone";
    39→const WAITING_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes
    40→const HOLD_DURATION_MS = 2000;
    41→const CANVAS_WIDTH = 1920;
    42→const CANVAS_HEIGHT = 1080;
    43→
    44→export default function MirrorPageWrapper() {
    45→  return (
    46→    <Suspense fallback={null}>
    47→      <MirrorPage />
    48→    </Suspense>
    49→  );
    50→}
    51→
    52→function MirrorPage() {
    53→  // ── Kiosk state ──
    54→  const [kioskState, setKioskState] = useState<KioskState>("attract");
    55→  const [activeUser, setActiveUser] = useState<ActiveUser | null>(null);
    56→  const waitingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    57→  const pendingQueueRef = useRef<ActiveUser | null | undefined>(undefined);
    58→
    59→  // ── Camera (hidden, 1080p for better pose accuracy) ──
    60→  const { videoRef, isReady: isCameraReady } = useCamera();
    61→
    62→  // ── Gesture recognition ──
    63→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    64→  const gestureKeyRef = useRef(0);
    65→  const [gestureKey, setGestureKey] = useState(0);
    66→  const [pendingGestureType, setPendingGestureType] = useState<GestureType | null>(null);
    67→  const holdKeyRef = useRef(0);
    68→  const [holdKey, setHoldKey] = useState(0);
    69→  const holdStartRef = useRef<number | null>(null);
    70→  const holdGestureRef = useRef<GestureType | null>(null);
    71→  const holdLastSeenRef = useRef<number>(0);
    72→  const holdRafRef = useRef<number>(0);
    73→
    74→  // ── Session state ──
    75→  const [sessionActive, setSessionActive] = useState(false);
    76→  const [isStarting, setIsStarting] = useState(false);
    77→
    78→  // ── Pose detection + clothing overlay ──
    79→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    80→
    81→  interface CanvasOutfit {
    82→    name: string;
    83→    items: ClothingItem[];
    84→    productInfo: PriceStripItem[];
    85→    originalImageUrls: string[];
    86→  }
    87→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    88→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    89→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    90→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    91→
    92→  // ── Outfit opacity for fade-in ──
    93→  const [outfitOpacity, setOutfitOpacity] = useState(1);
    94→
    95→  // ── Outfit animation state (like-collect / dislike-dismiss) ──
    96→  const [outfitAnimation, setOutfitAnimation] = useState<"none" | "like-collect" | "dislike-dismiss">("none");
    97→
    98→  // ── Liked outfits for the tray ──
    99→  const [likedOutfits, setLikedOutfits] = useState<LikedOutfitThumbnail[]>([]);
   100→
   101→  // ── Product carousel (fallback when no flat lays available) ──
   102→  const [carouselItems, setCarouselItems] = useState<ProductCard[]>([]);
   103→
   104→  // ── Debug overlay ──
   105→  const [debugMode, setDebugMode] = useState(false);
   106→
   107→  // ── Fit status tracking ──
   108→  const [fitStatuses, setFitStatuses] = useState<Map<string, FitMethod>>(new Map());
   109→
   110→  // ── Recap state ──
   111→  const [recapData, setRecapData] = useState<{
   112→    summary?: string;
   113→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   114→    stats?: { items_shown: number; likes: number; dislikes: number };
   115→    user_name?: string;
   116→  } | null>(null);
   117→
   118→  // ── STT config (live-tunable from admin panel) ──
   119→  const [sttConfig, setSttConfig] = useState<DeepgramSTTConfig | undefined>();
   120→
   121→  // ── Mira video avatar + voice ──
   122→  const mira = useMiraVideoAvatar();
   123→  const stt = useDeepgramSTT(sttConfig);
   124→
   125→  // ── Speech display state ──
   126→  const [speechText, setSpeechText] = useState("");
   127→  const [speechVisible, setSpeechVisible] = useState(false);
   128→  const speechFadeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   129→
   130→  // Queue transcripts while mira is speaking, send when quiet
   131→  const pendingTranscriptRef = useRef<string | null>(null);
   132→
   133→  // Sentence buffer for incremental TTS — flushes at sentence boundaries
   134→  const sentenceBufferRef = useRef<string>("");
   135→  // Track emotion for the current response (parsed from first chunk)
   136→  const currentEmotionRef = useRef<string>("idle");
   137→  // Track whether emotion has been detected for this response
   138→  const emotionDetectedRef = useRef(false);
   139→
   140→  // Track whether we just interrupted Mira (ignore stale mira_speech chunks)
   141→  const interruptedRef = useRef(false);
   142→
   143→  // Current user ID for session
   144→  const userId = activeUser?.id ?? null;
   145→
   146→  // ── Log kiosk state transitions ──
   147→  useEffect(() => {
   148→    console.log("[Mirror:State]", kioskState, activeUser ? `user=${activeUser.name}` : "");
   149→  }, [kioskState, activeUser]);
   150→
   151→  // ── Pose detection callback ──
   152→  const handlePoseUpdate = useCallback((result: PoseResult) => {
   153→    setCurrentPose(result);
   154→  }, []);
   155→
   156→  usePoseDetection({
   157→    videoRef,
   158→    isVideoReady: isCameraReady,
   159→    onPoseUpdate: handlePoseUpdate,
   160→  });
   161→
   162→  // ── Fit status callback ──
   163→  const handleFitStatus = useCallback((statuses: Map<string, FitMethod>) => {
   164→    setFitStatuses(statuses);
   165→  }, []);
   166→
   167→  // ── Connect socket and join mirror room ──
   168→  useEffect(() => {
   169→    socket.connect();
   170→    socket.emit("join_mirror_room");
   171→
   172→    const onConnect = () => console.log("[Mirror:Socket] Connected, id:", socket.id);
   173→    const onConnectError = (err: Error) => console.error("[Mirror:Socket] Connection error:", err.message);
   174→    const onDisconnect = (reason: string) => console.warn("[Mirror:Socket] Disconnected:", reason);
   175→
   176→    socket.on("connect", onConnect);
   177→    socket.on("connect_error", onConnectError);
   178→    socket.on("disconnect", onDisconnect);
   179→
   180→    return () => {
   181→      socket.off("connect", onConnect);
   182→      socket.off("connect_error", onConnectError);
   183→      socket.off("disconnect", onDisconnect);
   184→      socket.disconnect();
   185→    };
   186→  }, []);
   187→
   188→  // ── Fetch initial STT config + listen for admin updates ──
   189→  useEffect(() => {
   190→    getSTTConfig()
   191→      .then(setSttConfig)
   192→      .catch(() => console.warn("[Mirror] Failed to fetch STT config, using defaults"));
   193→
   194→    const handleSttConfigUpdated = (data: DeepgramSTTConfig) => {
   195→      console.log("[Mirror] STT config updated:", data);
   196→      setSttConfig(data);
   197→    };
   198→
   199→    socket.on("stt_config_updated", handleSttConfigUpdated);
   200→    return () => {
   201→      socket.off("stt_config_updated", handleSttConfigUpdated);
   202→    };
   203→  }, []);
   204→
   205→  // Join user-specific room when active user changes
   206→  useEffect(() => {
   207→    if (userId) {
   208→      socket.emit("join_room", { user_id: userId });
   209→    }
   210→  }, [userId]);
   211→
   212→  // ── Queue events (drives attract <-> waiting) ──
   213→  useEffect(() => {
   214→    const handleQueueUpdated = (data: {
   215→      active_user: ActiveUser | null;
   216→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   217→    }) => {
   218→      console.log("[Mirror] queue_updated:", data);
   219→      if (kioskState === "session") return;
   220→
   221→      if (kioskState === "recap") {
   222→        pendingQueueRef.current = data.active_user ?? null;
   223→        return;
   224→      }
   225→
   226→      if (data.active_user) {
   227→        setActiveUser(data.active_user);
   228→        setKioskState("waiting");
   229→      } else {
   230→        setActiveUser(null);
   231→        setKioskState("attract");
   232→      }
   233→    };
   234→
   235→    socket.on("queue_updated", handleQueueUpdated);
   236→    return () => {
   237→      socket.off("queue_updated", handleQueueUpdated);
   238→    };
   239→  }, [kioskState]);
   240→
   241→  // ── 2-minute timeout in waiting state ──
   242→  useEffect(() => {
   243→    if (kioskState === "waiting" && activeUser) {
   244→      waitingTimerRef.current = setTimeout(() => {
   245→        console.log("[Mirror] Waiting timeout — auto-skipping user");
   246→        skipQueueUser(activeUser.id).catch(() => {});
   247→      }, WAITING_TIMEOUT_MS);
   248→    }
   249→    return () => {
   250→      if (waitingTimerRef.current) {
   251→        clearTimeout(waitingTimerRef.current);
   252→        waitingTimerRef.current = null;
   253→      }
   254→    };
   255→  }, [kioskState, activeUser]);
   256→
   257→  // ── Session active from backend ──
   258→  useEffect(() => {
   259→    const handleSessionActive = () => {
   260→      setKioskState("session");
   261→      setSessionActive(true);
   262→      setIsStarting(false);
   263→      setCanvasOutfits([]);
   264→      setCanvasOutfitIndex(0);
   265→      setCarouselItems([]);
   266→      setOutfitOpacity(1);
   267→      setOutfitAnimation("none");
   268→      setLikedOutfits([]);
   269→      setSpeechText("");
   270→      setSpeechVisible(false);
   271→      mira.startSession();
   272→      stt.startListening();
   273→    };
   274→
   275→    socket.on("session_active", handleSessionActive);
   276→    return () => {
   277→      socket.off("session_active", handleSessionActive);
   278→    };
   279→    // eslint-disable-next-line react-hooks/exhaustive-deps
   280→  }, []);
   281→
   282→  // ── Mira speech events (sentence-level streaming) ──
   283→  useEffect(() => {
   284→    // Regex for sentence boundaries: .!? followed by a space or end of string
   285→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   286→
   287→    /**
   288→     * Flush complete sentences from the buffer to TTS.
   289→     * Returns any remaining partial sentence left in the buffer.
   290→     */
   291→    function flushSentences(buffer: string, emotion: string): string {
   292→      let remaining = buffer;
   293→
   294→      while (true) {
   295→        const match = SENTENCE_BOUNDARY.exec(remaining);
   296→        if (!match) break;
   297→
   298→        // Split at the sentence boundary (include the punctuation)
   299→        const endIdx = match.index + match[0].length;
   300→        const sentence = remaining.slice(0, endIdx).trim();
   301→        remaining = remaining.slice(endIdx);
   302→
   303→        if (sentence) {
   304→          // Capture sentence in closure for the onStart callback
   305→          const displaySentence = sentence;
   306→          mira.speakQueued(
   307→            sentence,
   308→            emotion as MiraEmotion,
   309→            () => {
   310→              // Fires when TTS actually starts playing this sentence
   311→              setSpeechText(displaySentence);
   312→              setSpeechVisible(true);
   313→              if (speechFadeTimerRef.current) {
   314→                clearTimeout(speechFadeTimerRef.current);
   315→              }
   316→            },
   317→          );
   318→        }
   319→      }
   320→
   321→      return remaining;
   322→    }
   323→
   324→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   325→      // Ignore stale chunks from the pre-interrupt response
   326→      if (interruptedRef.current) {
   327→        if (data.is_chunk === false) {
   328→          interruptedRef.current = false; // Old response ended
   329→        }
   330→        return;
   331→      }
   332→
   333→      // Fallback session detection
   334→      if (!sessionActive && !isStarting) {
   335→        setKioskState("session");
   336→        setSessionActive(true);
   337→        setIsStarting(false);
   338→        mira.startSession();
   339→        stt.startListening();
   340→      }
   341→
   342→      if (data.is_chunk !== false) {
   343→        // ── Streaming chunk ──
   344→        if (!data.text) return;
   345→
   346→        sentenceBufferRef.current += data.text;
   347→
   348→        // Detect emotion from keywords in accumulated text
   349→        if (!emotionDetectedRef.current) {
   350→          const detected = detectEmotionFromText(sentenceBufferRef.current);
   351→          if (detected !== "idle") {
   352→            currentEmotionRef.current = detected;
   353→            emotionDetectedRef.current = true;
   354→          }
   355→        }
   356→
   357→        // Flush any complete sentences to TTS immediately
   358→        sentenceBufferRef.current = flushSentences(
   359→          sentenceBufferRef.current,
   360→          currentEmotionRef.current,
   361→        );
   362→      } else {
   363→        // ── End of message ──
   364→        if (data.text) {
   365→          sentenceBufferRef.current += data.text;
   366→        }
   367→
   368→        // Detect emotion if we haven't yet (short responses)
   369→        if (!emotionDetectedRef.current) {
   370→          currentEmotionRef.current = detectEmotionFromText(sentenceBufferRef.current);
   371→        }
   372→
   373→        // Flush any remaining text as the final sentence
   374→        const remainder = sentenceBufferRef.current.trim();
   375→        if (remainder) {
   376→          const displayRemainder = remainder;
   377→          mira.speakQueued(
   378→            remainder,
   379→            currentEmotionRef.current as MiraEmotion,
   380→            () => {
   381→              // Fires when TTS actually starts playing this sentence
   382→              setSpeechText(displayRemainder);
   383→              setSpeechVisible(true);
   384→              if (speechFadeTimerRef.current) {
   385→                clearTimeout(speechFadeTimerRef.current);
   386→              }
   387→            },
   388→          );
   389→        }
   390→
   391→        // Signal end of queue — drain callback will reset avatar state
   392→        mira.flushQueue();
   393→
   394→        // Reset for next response
   395→        sentenceBufferRef.current = "";
   396→        currentEmotionRef.current = "idle";
   397→        emotionDetectedRef.current = false;
   398→      }
   399→    };
   400→
   401→    socket.on("mira_speech", handleSpeech);
   402→    return () => {
   403→      socket.off("mira_speech", handleSpeech);
   404→    };
   405→    // eslint-disable-next-line react-hooks/exhaustive-deps
   406→  }, [sessionActive, isStarting]);
   407→
   408→  // Fade out speech text 2s after mira stops speaking
   409→  useEffect(() => {
   410→    if (!mira.isSpeaking && speechVisible) {
   411→      speechFadeTimerRef.current = setTimeout(() => {
   412→        setSpeechVisible(false);
   413→      }, 2000);
   414→    }
   415→    return () => {
   416→      if (speechFadeTimerRef.current) {
   417→        clearTimeout(speechFadeTimerRef.current);
   418→        speechFadeTimerRef.current = null;
   419→      }
   420→    };
   421→  }, [mira.isSpeaking, speechVisible]);
   422→
   423→  // ── Tool result events (product recommendations) ──
   424→  useEffect(() => {
   425→    const handleToolResult = (data: {
   426→      type?: string;
   427→      tool?: string;
   428→      items?: { title: string; price?: string; [key: string]: unknown }[];
   429→      text?: string;
   430→      emotion?: string;
   431→      outfit_name?: string;
   432→    }) => {
   433→      const result = processToolResult(data);
   434→      if (!result) {
   435→        console.warn("[Mirror:ToolResult] Ignored — processToolResult returned null for:", data.type, data);
   436→        return;
   437→      }
   438→      console.log("[Mirror:ToolResult] Processed:", data.type, "canvas:", result.canvasItems.length, "carousel:", result.carouselCards.length);
   439→
   440→      // Always show carousel cards (doesn't need pose detection)
   441→      if (result.carouselCards.length > 0) {
   442→        setCarouselItems(result.carouselCards);
   443→      }
   444→
   445→      // Additionally populate canvas overlay (renders when pose available)
   446→      if (result.canvasItems.length > 0 && !currentPose) {
   447→        console.warn("[Mirror:ToolResult] Canvas items received but currentPose is null — overlay won't render until pose is detected");
   448→      }
   449→      if (result.canvasItems.length > 0) {
   450→        // Capture original product image URLs for the liked-items tray
   451→        const imageUrls = result.carouselCards
   452→          .map((card) => card.image_url)
   453→          .filter(Boolean);
   454→
   455→        setOutfitOpacity(0);
   456→        setCanvasOutfits((prev) => {
   457→          const next = [
   458→            ...prev,
   459→            {
   460→              name: result.outfitName || `Outfit ${prev.length + 1}`,
   461→              items: result.canvasItems,
   462→              productInfo: result.priceInfo,
   463→              originalImageUrls: imageUrls,
   464→            },
   465→          ];
   466→          setCanvasOutfitIndex(next.length - 1);
   467→          return next;
   468→        });
   469→        requestAnimationFrame(() => {
   470→          requestAnimationFrame(() => {
   471→            setOutfitOpacity(1);
   472→          });
   473→        });
   474→      }
   475→    };
   476→
   477→    socket.on("tool_result", handleToolResult);
   478→    return () => {
   479→      socket.off("tool_result", handleToolResult);
   480→    };
   481→  }, []);
   482→
   483→  // ── Session ended — show recap ──
   484→  useEffect(() => {
