   688→    const tick = () => {
   689→      holdRafRef.current = requestAnimationFrame(tick);
   690→
   691→      if (!holdGestureRef.current || !holdStartRef.current) return;
   692→
   693→      const now = Date.now();
   694→
   695→      // If gesture hasn't been seen in 300ms, cancel the hold
   696→      if (now - holdLastSeenRef.current > 300) {
   697→        holdGestureRef.current = null;
   698→        holdStartRef.current = null;
   699→        setPendingGestureType(null);
   700→        return;
   701→      }
   702→
   703→      // Hold completed → dispatch the gesture event + trigger animation
   704→      const elapsed = now - holdStartRef.current;
   705→      if (elapsed >= HOLD_DURATION_MS) {
   706→        const gestureType = holdGestureRef.current;
   707→
   708→        setLastGesture(gestureType);
   709→        gestureKeyRef.current += 1;
   710→        setGestureKey(gestureKeyRef.current);
