  1116→      {/* Like/dislike animation keyframes */}
  1117→      <style>{`
  1118→        .like-collect {
  1119→          animation: likeCollect 800ms ease-in forwards;
  1120→        }
  1121→        .dislike-dismiss {
  1122→          animation: dislikeDismiss 700ms ease-in forwards;
  1123→        }
  1124→        @keyframes likeCollect {
  1125→          0%   { transform: scale(1) translate(0, 0); opacity: 1; }
  1126→          100% { transform: scale(0.12) translate(600px, 400px); opacity: 0.3; }
  1127→        }
  1128→        @keyframes dislikeDismiss {
  1129→          0%   { transform: translateY(0); opacity: 1; filter: none; }
  1130→          100% { transform: translateY(80px); opacity: 0; filter: sepia(0.5) saturate(3) hue-rotate(-30deg); }
  1131→        }
  1132→      `}</style>
