  1139→            bottom: 20,
  1140→            right: 20,
  1141→            padding: "8px 12px",
  1142→            background: "rgba(0,0,0,0.7)",
  1143→            borderRadius: 8,
  1144→            color: "#fff",
  1145→            fontSize: "0.75rem",
  1146→            zIndex: 30,
  1147→            fontFamily: "monospace",
  1148→          }}
  1149→        >
  1150→          {Array.from(fitStatuses.entries()).map(([id, method]) => (
  1151→            <div key={id}>
  1152→              {id.slice(0, 8)}: {method === "precise" ? "anchor" : "quad"}
  1153→            </div>
  1154→          ))}
  1155→        </div>
  1156→      )}
  1157→    </main>
  1158→  );
  1159→}
  1160→
  1161→/* ---------- Waiting Countdown ---------- */
  1162→
  1163→function WaitingCountdown() {
  1164→  const [remaining, setRemaining] = useState(120);
  1165→
  1166→  useEffect(() => {
  1167→    const timer = setInterval(() => {
  1168→      setRemaining((s) => {
  1169→        if (s <= 0) return 0;
  1170→        return s - 1;
  1171→      });
  1172→    }, 1000);
  1173→    return () => clearInterval(timer);
  1174→  }, []);
  1175→
  1176→  const minutes = Math.floor(remaining / 60);
  1177→  const seconds = remaining % 60;
  1178→
  1179→  return (
  1180→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
  1181→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
  1182→    </p>
  1183→  );
  1184→}
