    39→export function processToolResult(data: ToolResultData): ProcessedToolResult | null {
    40→  if (!data.items || data.items.length === 0) {
    41→    console.warn("[MirrorV2:ToolResult] No items in:", data.type);
    42→    return null;
    43→  }
    44→
    45→  if (data.type === "display_product") {
    46→    console.log(`[MirrorV2:ToolResult] display_product received ${data.items.length} items, outfit: "${data.outfit_name}"`);
    47→    // Log raw item data for debugging the pipeline
    48→    for (const it of data.items) {
    49→      console.log(`[MirrorV2:ToolResult]   → "${it.title}" type=${it.type ?? "MISSING"} image_url=${it.image_url ? "yes" : "no"} cleaned=${it.cleaned_image_url ? "yes" : "no"} flat=${it.flat_image_url ? "yes" : "no"}`);
    50→    }
    51→
    52→    const canvasItems = mapToClothingItems(data.items);
    53→    const priceInfo: PriceStripItem[] = data.items.map((it) => ({
    54→      title: it.title,
    55→      price: it.price,
    56→    }));
    57→    const outfitName = data.outfit_name || "";
    58→
    59→    // Always populate carousel cards for immediate visual feedback
    60→    const carouselCards = mapItemsToCards(data.items);
    61→
    62→    if (canvasItems.length === 0 && data.items.length > 0) {
    63→      console.warn(`[MirrorV2:ToolResult] ⚠ ALL ${data.items.length} items filtered out by mapToClothingItems! Canvas will be empty. Likely causes: missing type field, or no cleaned_image_url/flat_image_url (Gemini flat lay generation may have failed).`);
    64→    }
    65→
    66→    return { canvasItems, carouselCards, priceInfo, outfitName };
    67→  }
    68→
    69→  if (data.type === "clothing_results") {
    70→    const carouselCards = mapItemsToCards(data.items);
    71→    if (carouselCards.length === 0) return null;
    72→    return { canvasItems: [], carouselCards, priceInfo: [], outfitName: "" };
    73→  }
    74→
    75→  console.warn("[MirrorV2:ToolResult] Unknown tool type:", data.type);
    76→  return null;
    77→}
    78→
    79→/** Map raw tool result items to ProductCard format for the carousel. */
    80→function mapItemsToCards(
    81→  items: NonNullable<ToolResultData["items"]>,
    82→): ProductCard[] {
    83→  return items
    84→    .filter((it) => it.image_url)
    85→    .map((it) => ({
    86→      product_id: it.product_id || crypto.randomUUID(),
    87→      title: it.title,
    88→      price: it.price || "",
    89→      image_url: it.image_url!,
    90→      link: it.link || "",
    91→      source: it.source || "",
    92→    }));
    93→}
