   278→    };
   279→    // eslint-disable-next-line react-hooks/exhaustive-deps
   280→  }, []);
   281→
   282→  // ── Mira speech events (sentence-level streaming) ──
   283→  useEffect(() => {
   284→    // Regex for sentence boundaries: .!? followed by a space or end of string
   285→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   286→
   287→    /**
   288→     * Flush complete sentences from the buffer to TTS.
   289→     * Returns any remaining partial sentence left in the buffer.
   290→     */
   291→    function flushSentences(buffer: string, emotion: string): string {
   292→      let remaining = buffer;
   293→
   294→      while (true) {
   295→        const match = SENTENCE_BOUNDARY.exec(remaining);
   296→        if (!match) break;
   297→
   298→        // Split at the sentence boundary (include the punctuation)
   299→        const endIdx = match.index + match[0].length;
   300→        const sentence = remaining.slice(0, endIdx).trim();
   301→        remaining = remaining.slice(endIdx);
   302→
   303→        if (sentence) {
   304→          // Capture sentence in closure for the onStart callback
   305→          const displaySentence = sentence;
   306→          mira.speakQueued(
   307→            sentence,
   308→            emotion as MiraEmotion,
   309→            () => {
   310→              // Fires when TTS actually starts playing this sentence
   311→              setSpeechText(displaySentence);
   312→              setSpeechVisible(true);
   313→              if (speechFadeTimerRef.current) {
   314→                clearTimeout(speechFadeTimerRef.current);
   315→              }
   316→            },
   317→          );
   318→        }
   319→      }
   320→
   321→      return remaining;
   322→    }
   323→
   324→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   325→      // Ignore stale chunks from the pre-interrupt response
   326→      if (interruptedRef.current) {
   327→        if (data.is_chunk === false) {
   328→          interruptedRef.current = false; // Old response ended
   329→        }
   330→        return;
   331→      }
   332→
   333→      // Fallback session detection
   334→      if (!sessionActive && !isStarting) {
   335→        setKioskState("session");
   336→        setSessionActive(true);
   337→        setIsStarting(false);
   338→        mira.startSession();
   339→        stt.startListening();
   340→      }
   341→
   342→      if (data.is_chunk !== false) {
   343→        // ── Streaming chunk ──
   344→        if (!data.text) return;
   345→
   346→        sentenceBufferRef.current += data.text;
   347→
   348→        // Detect emotion from keywords in accumulated text
   349→        if (!emotionDetectedRef.current) {
   350→          const detected = detectEmotionFromText(sentenceBufferRef.current);
   351→          if (detected !== "idle") {
   352→            currentEmotionRef.current = detected;
   353→            emotionDetectedRef.current = true;
   354→          }
   355→        }
   356→
   357→        // Flush any complete sentences to TTS immediately
   358→        sentenceBufferRef.current = flushSentences(
   359→          sentenceBufferRef.current,
   360→          currentEmotionRef.current,
   361→        );
   362→      } else {
   363→        // ── End of message ──
   364→        if (data.text) {
   365→          sentenceBufferRef.current += data.text;
   366→        }
   367→
   368→        // Detect emotion if we haven't yet (short responses)
   369→        if (!emotionDetectedRef.current) {
   370→          currentEmotionRef.current = detectEmotionFromText(sentenceBufferRef.current);
   371→        }
   372→
   373→        // Flush any remaining text as the final sentence
   374→        const remainder = sentenceBufferRef.current.trim();
   375→        if (remainder) {
   376→          const displayRemainder = remainder;
   377→          mira.speakQueued(
   378→            remainder,
   379→            currentEmotionRef.current as MiraEmotion,
   380→            () => {
   381→              // Fires when TTS actually starts playing this sentence
   382→              setSpeechText(displayRemainder);
   383→              setSpeechVisible(true);
   384→              if (speechFadeTimerRef.current) {
   385→                clearTimeout(speechFadeTimerRef.current);
   386→              }
   387→            },
   388→          );
   389→        }
   390→
   391→        // Signal end of queue — drain callback will reset avatar state
   392→        mira.flushQueue();
   393→
   394→        // Reset for next response
   395→        sentenceBufferRef.current = "";
   396→        currentEmotionRef.current = "idle";
   397→        emotionDetectedRef.current = false;
   398→      }
   399→    };
   400→
   401→    socket.on("mira_speech", handleSpeech);
   402→    return () => {
   403→      socket.off("mira_speech", handleSpeech);
   404→    };
   405→    // eslint-disable-next-line react-hooks/exhaustive-deps
   406→  }, [sessionActive, isStarting]);
   407→
   408→  // Fade out speech text 2s after mira stops speaking
   409→  useEffect(() => {
   410→    if (!mira.isSpeaking && speechVisible) {
   411→      speechFadeTimerRef.current = setTimeout(() => {
   412→        setSpeechVisible(false);
   413→      }, 2000);
   414→    }
   415→    return () => {
   416→      if (speechFadeTimerRef.current) {
   417→        clearTimeout(speechFadeTimerRef.current);
   418→        speechFadeTimerRef.current = null;
   419→      }
   420→    };
   421→  }, [mira.isSpeaking, speechVisible]);
   422→
   423→  // ── Tool result events (product recommendations) ──
   424→  useEffect(() => {
   425→    const handleToolResult = (data: {
