   481→  }, []);
   482→
   483→  // ── Session ended — show recap ──
   484→  useEffect(() => {
   485→    const handleSessionEnded = (data?: {
   486→      summary?: string;
   487→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   488→      stats?: { items_shown: number; likes: number; dislikes: number };
   489→      user_name?: string;
