    34→/** Parse [emotion:X] prefix tag from Claude's response. */
    35→export function parseEmotionTag(text: string): {
    36→  emotion: MiraEmotion;
    37→  cleanText: string;
    38→} {
    39→  const match = text.match(/^\[emotion:(\w+)\]\s*/i);
    40→  if (match) {
    41→    const rawTag = match[1].toLowerCase();
    42→    
    43→    // Check if it's a valid emotion
    44→    if (VALID_EMOTIONS.includes(rawTag as MiraEmotion)) {
    45→      return {
    46→        emotion: rawTag as MiraEmotion,
    47→        cleanText: text.slice(match[0].length),
    48→      };
    49→    }
    50→    
    51→    // Check aliases
    52→    if (rawTag in EMOTION_ALIASES) {
    53→      return {
    54→        emotion: EMOTION_ALIASES[rawTag],
    55→        cleanText: text.slice(match[0].length),
    56→      };
    57→    }
    58→    
    59→    // Unknown emotion, default to idle
    60→    console.warn(`[EmotionParser] Unknown emotion: ${rawTag}, defaulting to idle`);
    61→    return {
    62→      emotion: "idle",
    63→      cleanText: text.slice(match[0].length),
    64→    };
    65→  }
    66→  
    67→  return { emotion: "idle", cleanText: text };
    68→}
    69→
    70→/**
    71→ * Detect emotion from text content using keyword matching.
    72→ * Used as a fallback when no explicit emotion tag is present.
    73→ */
    74→export function detectEmotionFromText(text: string): MiraEmotion {
    75→  const lower = text.toLowerCase();
    76→  
    77→  // Excited keywords
    78→  if (/\b(amazing|awesome|incredible|fantastic|wow|omg|oh my god|can't wait|so excited|yay|woohoo)\b/.test(lower)) {
    79→    return "excited";
    80→  }
    81→  
    82→  // Happy keywords
    83→  if (/\b(happy|glad|pleased|delighted|love|wonderful|great|nice|lovely)\b/.test(lower)) {
    84→    return "happy";
    85→  }
    86→  
    87→  // Sassy keywords
    88→  if (/\b(obviously|clearly|duh|honey|sweetie|girl|please|excuse me|well well|oh really)\b/.test(lower)) {
    89→    return "sassy";
    90→  }
    91→  
    92→  // Judgy keywords
    93→  if (/\b(really\?|seriously\?|hmm|suspicious|doubt|questionable|uh huh|sure jan)\b/.test(lower)) {
    94→    return "judgy";
    95→  }
    96→  
    97→  // Concerned keywords
    98→  if (/\b(worried|concern|careful|watch out|be safe|oh no|uh oh|trouble)\b/.test(lower)) {
    99→    return "concerned";
   100→  }
   101→  
   102→  // Disappointed keywords
   103→  if (/\b(unfortunately|sadly|sorry to|bad news|disappointing|bummer|too bad)\b/.test(lower)) {
   104→    return "disappointed";
   105→  }
   106→  
   107→  // Surprised keywords
   108→  if (/\b(what\!|no way|seriously|really\!|oh\!|whoa|wait what|huh)\b/.test(lower)) {
